import { useState } from "react";

const products = [
  { id: 1, name: "Velvet Blazer", category: "Men", price: 8500, originalPrice: 12000, image: "data:image/jpeg;base64,", badge: "Sale", rating: 4.8, reviews: 124 },
  { id: 2, name: "Silk Evening Dress", category: "Women", price: 11200, originalPrice: null, image: "data:image/jpeg;base64,", badge: "New", rating: 4.9, reviews: 87 },
  { id: 3, name: "Leather Crossbody Bag", category: "Women", price: 6400, originalPrice: 9000, image: "data:image/jpeg;base64,", badge: "Sale", rating: 4.7, reviews: 203 },
  { id: 4, name: "Classic Oxford Shoes", category: "Men", price: 9800, originalPrice: null, image: "data:image/jpeg;base64,", badge: null, rating: 4.6, reviews: 56 },
  { id: 5, name: "Kids Party Frock", category: "Kids", price: 3200, originalPrice: 4500, image: "data:image/jpeg;base64,", badge: "Sale", rating: 4.9, reviews: 311 },
  { id: 6, name: "Cashmere Turtleneck", category: "Women", price: 7600, originalPrice: null, image: "data:image/jpeg;base64,", badge: "New", rating: 4.5, reviews: 44 },
  { id: 7, name: "Slim Fit Chinos", category: "Men", price: 4200, originalPrice: 5800, image: "data:image/jpeg;base64,", badge: "Sale", rating: 4.4, reviews: 178 },
  { id: 8, name: "Kids Denim Jacket", category: "Kids", price: 2800, originalPrice: null, image: "data:image/jpeg;base64,", badge: "New", rating: 4.7, reviews: 92 },
];

const categories = ["All", "Men", "Women", "Kids"];
const sortOptions = ["Featured", "Price: Low to High", "Price: High to Low", "Top Rated"];

const StarIcon = ({ filled }) => (
  <svg width="12" height="12" viewBox="0 0 24 24" fill={filled ? "#c9a96e" : "none"} stroke="#c9a96e" strokeWidth="2">
    <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2" />
  </svg>
);

const ShoppingList = () => {
  const [activeCategory, setActiveCategory] = useState("All");
  const [sortBy, setSortBy] = useState("Featured");
  const [wishlist, setWishlist] = useState([]);
  const [cart, setCart] = useState([]);
  const [toast, setToast] = useState(null);

  const toggleWishlist = (id) => {
    setWishlist((prev) =>
      prev.includes(id) ? prev.filter((i) => i !== id) : [...prev, id]
    );
  };

  const addToCart = (product) => {
    setCart((prev) => [...prev, product.id]);
    setToast(`"${product.name}" added to cart!`);
    setTimeout(() => setToast(null), 2500);
  };

  const filtered = products
    .filter((p) => activeCategory === "All" || p.category === activeCategory)
    .sort((a, b) => {
      if (sortBy === "Price: Low to High") return a.price - b.price;
      if (sortBy === "Price: High to Low") return b.price - a.price;
      if (sortBy === "Top Rated") return b.rating - a.rating;
      return 0;
    });

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@300;400;500&display=swap');

        * { box-sizing: border-box; margin: 0; padding: 0; }

        :root {
          --bg: #0a0a0a;
          --surface: #141414;
          --card: #111111;
          --accent: #c9a96e;
          --accent-light: #e8c98a;
          --text: #f0ede8;
          --muted: #888;
          --border: rgba(201,169,110,0.15);
          --radius: 4px;
        }

        .shop-page {
          background: var(--bg);
          min-height: 100vh;
          font-family: 'DM Sans', sans-serif;
          color: var(--text);
        }

        /* HERO BANNER */
        .shop-hero {
          background: linear-gradient(135deg, #0f0f0f 0%, #1a1408 50%, #0f0f0f 100%);
          border-bottom: 1px solid var(--border);
          padding: 60px 40px 50px;
          text-align: center;
          position: relative;
          overflow: hidden;
        }

        .shop-hero::before {
          content: '';
          position: absolute;
          inset: 0;
          background: radial-gradient(ellipse 60% 80% at 50% 50%, rgba(201,169,110,0.07) 0%, transparent 70%);
        }

        .hero-eyebrow {
          font-size: 11px;
          letter-spacing: 4px;
          text-transform: uppercase;
          color: var(--accent);
          margin-bottom: 14px;
        }

        .hero-title {
          font-family: 'Playfair Display', serif;
          font-size: clamp(32px, 5vw, 58px);
          font-weight: 700;
          color: var(--text);
          line-height: 1.1;
          margin-bottom: 16px;
          position: relative;
        }

        .hero-title span { color: var(--accent); }

        .hero-subtitle {
          color: var(--muted);
          font-size: 15px;
          max-width: 460px;
          margin: 0 auto;
          line-height: 1.7;
          position: relative;
        }

        /* CONTROLS */
        .shop-controls {
          display: flex;
          align-items: center;
          justify-content: space-between;
          flex-wrap: wrap;
          gap: 16px;
          padding: 28px 40px;
          border-bottom: 1px solid var(--border);
          background: var(--surface);
          position: sticky;
          top: 0;
          z-index: 50;
        }

        .category-tabs {
          display: flex;
          gap: 6px;
        }

        .tab-btn {
          background: none;
          border: 1px solid transparent;
          color: var(--muted);
          font-family: 'DM Sans', sans-serif;
          font-size: 12px;
          font-weight: 500;
          letter-spacing: 1px;
          text-transform: uppercase;
          padding: 8px 20px;
          border-radius: 30px;
          cursor: pointer;
          transition: all 0.25s ease;
        }

        .tab-btn:hover {
          color: var(--accent);
          border-color: var(--border);
        }

        .tab-btn.active {
          background: var(--accent);
          color: #0a0a0a;
          border-color: var(--accent);
          font-weight: 600;
        }

        .sort-select {
          background: var(--card);
          border: 1px solid var(--border);
          color: var(--text);
          font-family: 'DM Sans', sans-serif;
          font-size: 13px;
          padding: 8px 14px;
          border-radius: var(--radius);
          cursor: pointer;
          outline: none;
          transition: border-color 0.2s;
        }

        .sort-select:focus {
          border-color: var(--accent);
        }

        .results-count {
          color: var(--muted);
          font-size: 13px;
        }

        .results-count strong {
          color: var(--text);
        }

        /* PRODUCT GRID */
        .product-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(270px, 1fr));
          gap: 1px;
          background: var(--border);
          padding: 0;
        }

        /* PRODUCT CARD */
        .product-card {
          background: var(--card);
          display: flex;
          flex-direction: column;
          position: relative;
          overflow: hidden;
          transition: background 0.3s ease;
          cursor: pointer;
        }

        .product-card:hover {
          background: #181818;
        }

        .product-card:hover .card-overlay {
          opacity: 1;
        }

        .product-card:hover .product-img {
          transform: scale(1.04);
        }

        /* IMAGE */
        .img-wrap {
          position: relative;
          overflow: hidden;
          aspect-ratio: 3/4;
          background: #0e0e0e;
        }

        .product-img {
          width: 100%;
          height: 100%;
          object-fit: cover;
          transition: transform 0.5s ease;
        }

        /* BADGE */
        .badge {
          position: absolute;
          top: 14px;
          left: 14px;
          font-size: 10px;
          font-weight: 700;
          letter-spacing: 1.5px;
          text-transform: uppercase;
          padding: 4px 10px;
          border-radius: 2px;
          z-index: 2;
        }

        .badge-sale {
          background: #c0392b;
          color: #fff;
        }

        .badge-new {
          background: var(--accent);
          color: #0a0a0a;
        }

        /* WISHLIST BTN */
        .wish-btn {
          position: absolute;
          top: 12px;
          right: 12px;
          width: 36px;
          height: 36px;
          border-radius: 50%;
          background: rgba(10,10,10,0.7);
          border: 1px solid var(--border);
          display: flex;
          align-items: center;
          justify-content: center;
          cursor: pointer;
          z-index: 2;
          transition: background 0.2s, border-color 0.2s;
          backdrop-filter: blur(4px);
        }

        .wish-btn:hover, .wish-btn.active {
          background: rgba(201,169,110,0.15);
          border-color: var(--accent);
        }

        .wish-btn svg {
          width: 15px;
          height: 15px;
          stroke: var(--accent);
          transition: fill 0.2s;
        }

        .wish-btn.active svg {
          fill: var(--accent);
        }

        /* CARD OVERLAY */
        .card-overlay {
          position: absolute;
          bottom: 0;
          left: 0;
          right: 0;
          opacity: 0;
          transition: opacity 0.3s ease;
          z-index: 3;
        }

        .add-cart-btn {
          width: 100%;
          background: var(--accent);
          color: #0a0a0a;
          border: none;
          padding: 14px;
          font-family: 'DM Sans', sans-serif;
          font-size: 12px;
          font-weight: 700;
          letter-spacing: 2px;
          text-transform: uppercase;
          cursor: pointer;
          transition: background 0.2s;
        }

        .add-cart-btn:hover {
          background: var(--accent-light);
        }

        /* CARD INFO */
        .card-info {
          padding: 18px 20px 22px;
          flex: 1;
          display: flex;
          flex-direction: column;
          gap: 8px;
          border-top: 1px solid rgba(255,255,255,0.04);
        }

        .card-category {
          font-size: 10px;
          letter-spacing: 2px;
          text-transform: uppercase;
          color: var(--accent);
        }

        .card-name {
          font-family: 'Playfair Display', serif;
          font-size: 17px;
          font-weight: 600;
          color: var(--text);
          line-height: 1.3;
        }

        .card-rating {
          display: flex;
          align-items: center;
          gap: 6px;
        }

        .stars {
          display: flex;
          gap: 2px;
        }

        .rating-text {
          font-size: 12px;
          color: var(--muted);
        }

        .card-price {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-top: 4px;
        }

        .price-now {
          font-size: 18px;
          font-weight: 600;
          color: var(--text);
        }

        .price-old {
          font-size: 13px;
          color: var(--muted);
          text-decoration: line-through;
        }

        .discount-tag {
          font-size: 11px;
          color: #e74c3c;
          font-weight: 600;
        }

        /* TOAST */
        .toast {
          position: fixed;
          bottom: 30px;
          left: 50%;
          transform: translateX(-50%) translateY(20px);
          background: var(--surface);
          border: 1px solid var(--accent);
          color: var(--text);
          padding: 12px 28px;
          border-radius: 30px;
          font-size: 13.5px;
          font-weight: 500;
          opacity: 0;
          pointer-events: none;
          transition: all 0.35s ease;
          z-index: 9999;
          white-space: nowrap;
          box-shadow: 0 8px 32px rgba(201,169,110,0.12);
        }

        .toast.show {
          opacity: 1;
          transform: translateX(-50%) translateY(0);
        }

        /* EMPTY STATE */
        .empty-state {
          text-align: center;
          padding: 80px 20px;
          color: var(--muted);
          font-size: 15px;
          grid-column: 1 / -1;
          background: var(--card);
        }

        /* RESPONSIVE */
        @media (max-width: 768px) {
          .shop-hero { padding: 40px 20px 36px; }
          .shop-controls {
            padding: 18px 20px;
            top: 0;
          }
          .category-tabs { flex-wrap: wrap; }
          .tab-btn { font-size: 11px; padding: 7px 14px; }
          .product-grid { grid-template-columns: repeat(2, 1fr); }
          .card-overlay { opacity: 1; }
        }

        @media (max-width: 480px) {
          .product-grid { grid-template-columns: 1fr; }
          .shop-controls { flex-direction: column; align-items: flex-start; }
        }
      `}</style>

      <div className="shop-page">
        {/* Hero */}
        <section className="shop-hero">
          <p className="hero-eyebrow">✦ New Season Collection ✦</p>
          <h1 className="hero-title">Dress to <span>Impress</span></h1>
          <p className="hero-subtitle">
            Curated luxury fashion for every occasion — from street style to red carpet.
          </p>
        </section>

        {/* Controls */}
        <div className="shop-controls">
          <div className="category-tabs">
            {categories.map((cat) => (
              <button
                key={cat}
                className={`tab-btn ${activeCategory === cat ? "active" : ""}`}
                onClick={() => setActiveCategory(cat)}
              >
                {cat}
              </button>
            ))}
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: "16px", flexWrap: "wrap" }}>
            <span className="results-count">
              <strong>{filtered.length}</strong> items
            </span>
            <select
              className="sort-select"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
            >
              {sortOptions.map((o) => (
                <option key={o} value={o}>{o}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Product Grid */}
        <div className="product-grid">
          {filtered.length === 0 ? (
            <div className="empty-state">No products found in this category.</div>
          ) : (
            filtered.map((product) => {
              const discount = product.originalPrice
                ? Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)
                : null;
              const isWished = wishlist.includes(product.id);

              return (
                <div className="product-card" key={product.id}>
                  <div className="img-wrap">
                    <img
                      src={product.image}
                      alt={product.name}
                      className="product-img"
                    />

                    {product.badge && (
                      <span className={`badge ${product.badge === "Sale" ? "badge-sale" : "badge-new"}`}>
                        {product.badge}
                      </span>
                    )}

                    <button
                      className={`wish-btn ${isWished ? "active" : ""}`}
                      onClick={() => toggleWishlist(product.id)}
                      aria-label="Wishlist"
                    >
                      <svg viewBox="0 0 24 24" strokeWidth="1.5">
                        <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
                      </svg>
                    </button>

                    <div className="card-overlay">
                      <button className="add-cart-btn" onClick={() => addToCart(product)}>
                        + Add to Cart
                      </button>
                    </div>
                  </div>

                  <div className="card-info">
                    <span className="card-category">{product.category}</span>
                    <h3 className="card-name">{product.name}</h3>

                    <div className="card-rating">
                      <div className="stars">
                        {[1, 2, 3, 4, 5].map((s) => (
                          <StarIcon key={s} filled={s <= Math.round(product.rating)} />
                        ))}
                      </div>
                      <span className="rating-text">{product.rating} ({product.reviews})</span>
                    </div>

                    <div className="card-price">
                      <span className="price-now">Rs. {product.price.toLocaleString()}</span>
                      {product.originalPrice && (
                        <>
                          <span className="price-old">Rs. {product.originalPrice.toLocaleString()}</span>
                          <span className="discount-tag">-{discount}%</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* Toast Notification */}
        <div className={`toast ${toast ? "show" : ""}`}>
          🛒 {toast}
        </div>
      </div>
    </>
  );
};

export default ShoppingList;

